    public CallGraph graph = new CallGraph();
    
    // 延迟边：{callSiteId, calleeName, callSiteLine} {Env} {calleeType}
    // calleName global.procedure name 即为id
    public List<PendingEdges> pendingEdges = new ArrayList<>();
    public int callSiteCounter = 0;

    public mySymbol.Type intType = mySymbol.PrimitiveType.INTEGER,
                boolType = mySymbol.PrimitiveType.BOOLEAN,
                errorType = mySymbol.PrimitiveType.ERROR;

    public void report_error(String message, Object info) {
        StringBuilder m = new StringBuilder("Error ");
        if (info instanceof java_cup.runtime.Symbol) 
            m.append( "("+info.toString()+")" );
            
        m.append(" : "+message);
        System.out.println(m);
    }

    public void report_fatal_error(String message, Object info) {
        report_error(message, info);
        throw new RuntimeException("Fatal Syntax Error");
    }
    
    public Parser(OberonScanner s) throws SyntacticException  {
        super(s);
        mySymbol.Env.reset();

        mySymbol.Env.addSymbol_s("INTEGER", intType);
        mySymbol.Env.addSymbol_s("BOOLEAN", boolType);
        
        mySymbol.Parameter readParam = new mySymbol.Parameter("value", intType, true);
        mySymbol.Parameter writeParam = new mySymbol.Parameter("value", intType, false);
        mySymbol.Env.addSymbol_s("WRITE", new mySymbol.FormalParameters(readParam));
        mySymbol.Env.addSymbol_s("READ", new mySymbol.FormalParameters(writeParam));
        mySymbol.Env.addSymbol_s("WRITELN", new mySymbol.FormalParameters());
    }

    // 最终建图
    public void buildCallGraph() throws Exception {
        for (PendingEdges edge : pendingEdges) {
            mySymbol.Env calleeEnv = edge.getCallerEnv();
            List<mySymbol.Type> calleeParamTypes = edge.getParamTypes();
            String calleeName = edge.getCalleeName();
            int callSiteLine = edge.getCallSiteLine();
            String callSiteId = edge.getCallSiteId();
            while(calleeEnv != null) {
                String EnvName = calleeEnv.toString();
                mySymbol.TableSymbol sym = calleeEnv.lookupLocal(calleeName);
                if(sym != null && sym.getKind().equals("FORMALPARAMETERS")) {
                    mySymbol.FormalParameters fp = (mySymbol.FormalParameters) sym;
                    String errorString = fp.checkTypesWithMessage(calleeParamTypes);
                    if(errorString!=null) {
                        ErrorReport.reportError(ErrorType.TypeMismatchedException, callSiteLine, errorString);
                    }
                    graph.addEdge(callSiteId, EnvName + "." + calleeName);
                    break;
                }
                calleeEnv = calleeEnv.getFather();
            }
        }
        graph.show();
    }


